62	SigSpec RTLILBuilder::ReduceBool(SigSpec a)
63	{
64		if (a.is_fully_const())
65			return RTLIL::const_reduce_bool(a.as_const(), RTLIL::Const(), false, false, 1);
66		if (a.size() == 1)
67			return a[0];
