74	SigSpec RTLILBuilder::Demux(SigSpec a, SigSpec s)
75	{
76		log_assert(s.size() < 24);
77		SigSpec zeropad(RTLIL::S0, a.size());
78		if (s.is_fully_const()) {
79			int idx_const = s.as_const().as_int();
80			return {zeropad.repeat((1 << s.size()) - 1 - idx_const), a, zeropad.repeat(idx_const)};
81		}
82		auto [id, y] = add_y_wire(a.size() << s.size());
83		bless_cell(canvas->addDemux(id, a, s, y));
84		return y;
85	}
