207	SigSpec RTLILBuilder::Shift(SigSpec a, bool a_signed, SigSpec b, bool b_signed, int result_width)
208	{
209		if (a.is_fully_const() && b.is_fully_const())
210			return RTLIL::const_shift(a.as_const(), b.as_const(), a_signed, b_signed, result_width);
211	
212		if (b.is_fully_const() && b.size() < 24) {
213			log_assert(!a.empty());
214			int shift_amount = b.as_int(b_signed);
215			RTLIL::SigSpec ret;
216			int i, j;
217			for (i = shift_amount, j = 0; j < result_width; i++, j++) {
218				if (a_signed && i >= a.size())
219					ret.append(a.msb());
220				else if (i >= a.size() || i < 0)
221					ret.append(RTLIL::S0);
222				else
223					ret.append(a[i]);
224			}
225			return ret;
226		}
227	
228		auto [id, y] = add_y_wire(result_width);
229		Cell *cell = canvas->addCell(id, ID($shift));
230		cell->parameters[Yosys::ID::A_SIGNED] = a_signed;
231		cell->parameters[Yosys::ID::B_SIGNED] = b_signed;
232		cell->parameters[Yosys::ID::A_WIDTH] = a.size();
233		cell->parameters[Yosys::ID::B_WIDTH] = b.size();
234		cell->parameters[Yosys::ID::Y_WIDTH] = y.size();
235		cell->setPort(Yosys::ID::A, a);
236		cell->setPort(Yosys::ID::B, b);
237		cell->setPort(Yosys::ID::Y, y);
238		bless_cell(cell);
239		return y;
240	}
