462	void RTLILBuilder::connect(SigSpec lhs, SigSpec rhs)
463	{
464		log_assert(lhs.size() == rhs.size());
465		if (!lhs.empty()) {
466			Cell *cell = canvas->addBuf(new_id(), rhs, lhs);
467			bless_cell(cell);
468		}
469	}
