471	// Synthesizes two single-edge FFs (one posedge, one negedge) with the same D input,
472	// then uses a mux controlled by the clock to select the appropriate FF output.
473	void RTLILBuilder::add_dual_edge_aldff(const std::string &base_name, RTLIL::SigSpec clk,
474			RTLIL::SigSpec aload, RTLIL::SigSpec d, RTLIL::SigSpec q, RTLIL::SigSpec ad,
475			bool aload_polarity)
476	{
477		RTLIL::Wire *pos_q = canvas->addWire(
478				canvas->uniquify(Yosys::stringf("%s$pos$q", base_name.c_str())), d.size());
479	
480		RTLIL::Wire *neg_q = canvas->addWire(
481				canvas->uniquify(Yosys::stringf("%s$neg$q", base_name.c_str())), d.size());
482	
483		if (aload.is_fully_def() && aload.size() == 1 && aload.as_bool() != aload_polarity) {
484			RTLIL::Cell *pos_ff =
485					canvas->addDff(canvas->uniquify(Yosys::stringf("%s$pos", base_name.c_str())), clk,
486							d, pos_q, /*edge_polarity=*/true);
487			bless_cell(pos_ff);
488	
489			// Create negedge FF
490			RTLIL::Cell *neg_ff =
491					canvas->addDff(canvas->uniquify(Yosys::stringf("%s$neg", base_name.c_str())), clk,
492							d, neg_q, /*edge_polarity=*/false);
493			bless_cell(neg_ff);
494		} else {
495			RTLIL::Cell *pos_ff =
496					canvas->addAldff(canvas->uniquify(Yosys::stringf("%s$pos", base_name.c_str())), clk,
497							aload, d, pos_q, ad,
498							/*clk_polarity=*/true, aload_polarity);
499			bless_cell(pos_ff);
500	
501			RTLIL::Cell *neg_ff =
502					canvas->addAldff(canvas->uniquify(Yosys::stringf("%s$neg", base_name.c_str())), clk,
503							aload, d, neg_q, ad,
504							/*clk_polarity=*/false, aload_polarity);
505			bless_cell(neg_ff);
506		}
507	
508		// behaviour: when clk=0: select neg_q (captures on negedge), when clk=1: select pos_q (captures
509		// on posedge)
510		RTLIL::Cell *mux = canvas->addMux(canvas->uniquify(Yosys::stringf("%s$mux", base_name.c_str())),
511				/*A=*/neg_q, /*B=*/pos_q, /*S=*/clk, /*Y=*/q);
512		bless_cell(mux);
513	}
