559	SigSpec RTLILBuilder::CountOnes(SigSpec sig, int result_width)
560	{
561		SigSpec ret;
562		auto width = sig.size();
563		if (width == 0) {
564			ret = RTLIL::Const(0, 1);
565		} else if (width == 1) {
566			// Single bit
567			ret = sig;
568		} else {
569			// Build tree of adders
570			std::vector<RTLIL::SigSpec> curr_level;
571			for (int i = 0; i < width; i++) {
572				RTLIL::SigSpec bit = sig[i];
573				bit.extend_u0(result_width);
574				curr_level.push_back(bit);
575			}
576	
577			while (curr_level.size() > 1) {
578				std::vector<RTLIL::SigSpec> nxt_level;
579				for (size_t i = 0; i + 1 < curr_level.size(); i += 2) {
580					auto sum = Biop(
581							ID($add), curr_level[i], curr_level[i + 1], false, false, result_width);
582					if (sum.size() < result_width)
583						sum.extend_u0(result_width);
584					nxt_level.push_back(sum);
585				}
586				if (curr_level.size() % 2 == 1) {
587					nxt_level.push_back(curr_level.back());
588				}
589				curr_level = std::move(nxt_level);
590			}
591			ret = curr_level[0];
592		}
593		// Extend to expected type width
594		ret.extend_u0(result_width);
595		return ret;
596	}
597	
598	SigSpec RTLILBuilder::Clog2(SigSpec sig, int result_width)
599	{
600		int width = sig.size();
601	
602		if (width == 0)
603			return RTLIL::Const(0, result_width);
604	
605		SigSpec n_minus_1 = Biop(ID($sub), sig, RTLIL::Const(1, width), false, false, width);
606	
607		SigSpec result = RTLIL::Const(0, result_width);
608		for (int i = 0; i < width; i++)
609			result = Mux(result, RTLIL::Const(i + 1, result_width), n_minus_1[i]);
610	
611		SigSpec n_not_zero = ReduceBool(sig);
612		return Mux(RTLIL::Const(0, result_width), result, n_not_zero);
613	}
614	
615	static const RTLIL::Const reverse_data(RTLIL::Const &orig, int width)
616	{
617		std::vector<RTLIL::State> bits;
618		log_assert(orig.size() % width == 0);
619		bits.reserve(orig.size());
620		for (int i = orig.size() - width; i >= 0; i -= width)
621			bits.insert(bits.end(), orig.begin() + i, orig.begin() + i + width);
622		return bits;
623	}
