127	void TimingPatternInterpretor::interpret_async_pattern(const ast::ProceduralBlockSymbol &symbol,
128			std::vector<const ast::SignalEventControl *> triggers, const ast::Statement &body)
129	{
130		log_assert(symbol.getBody().kind == ast::StatementKind::Timed);
131		const auto &timed = symbol.getBody().as<ast::TimedStatement>();
132		const ast::Statement *stmt = &body;
133	
134		std::vector<AsyncBranch> found_async;
135		const ast::StatementBlockSymbol *prologue_block = nullptr;
136		std::vector<const ast::Statement *> prologue;
137		bool did_something = true;
138		while (did_something) {
139			did_something = false;
140	
141			if (prologue_block == nullptr && stmt->kind == ast::StatementKind::Block &&
142					stmt->as<ast::BlockStatement>().blockKind == ast::StatementBlockKind::Sequential) {
143				prologue_block = stmt->as<ast::BlockStatement>().blockSymbol;
144				stmt = &stmt->as<ast::BlockStatement>().body;
145				did_something = true;
146			}
147	
148			if (stmt->kind == ast::StatementKind::List && triggers.size() > 1) {
149				auto &list = stmt->as<ast::StatementList>().list;
150				std::vector<const ast::Statement *> pending_prologue;
151				for (size_t i = 0; i < list.size(); i++) {
152					auto &inner_stmt = list[i];
153					if (inner_stmt->kind == ast::StatementKind::ExpressionStatement ||
154							inner_stmt->kind == ast::StatementKind::VariableDeclaration) {
155						pending_prologue.push_back(inner_stmt);
156					} else if (i == list.size() - 1) {
157						stmt = inner_stmt;
158						prologue.insert(
159								prologue.end(), pending_prologue.begin(), pending_prologue.end());
160						pending_prologue.clear();
161						did_something = true;
162						break;
163					} else {
164						break;
165					}
166				}
167	
168				if (!pending_prologue.empty()) {
169					break;
170				}
171			}
172		}
173	
174		// Keep inferring asynchronous loads until we get to a single remaining edge trigger
175		while (triggers.size() > 1) {
176			if (stmt->kind != ast::StatementKind::Conditional ||
177					stmt->as<ast::ConditionalStatement>().check != ast::UniquePriorityCheck::None ||
178					stmt->as<ast::ConditionalStatement>().conditions.size() != 1 ||
179					stmt->as<ast::ConditionalStatement>().conditions[0].pattern ||
180					!stmt->as<ast::ConditionalStatement>().ifFalse) {
181				auto &diag = issuer.add_diag(diag::ExpectingIfElseAload, stmt->sourceRange);
182				diag.addNote(diag::NoteDuplicateEdgeSense, timed.timing.sourceRange);
183				return;
184			}
185	
186			auto &cond_stmt = stmt->as<ast::ConditionalStatement>();
187			const ast::Expression *condition = cond_stmt.conditions[0].expr;
188	
189			bool did_something = true, polarity = true;
190			while (did_something) {
191				did_something = false;
192	
193				if (condition->kind == ast::ExpressionKind::UnaryOp &&
194						(condition->as<ast::UnaryExpression>().op == ast::UnaryOperator::LogicalNot ||
195								condition->as<ast::UnaryExpression>().op ==
196										ast::UnaryOperator::BitwiseNot)) {
197					polarity = !polarity;
198					condition = &condition->as<ast::UnaryExpression>().operand();
199					did_something = true;
200				}
201	
202				if (condition->kind == ast::ExpressionKind::BinaryOp &&
203						condition->as<ast::BinaryExpression>().op == ast::BinaryOperator::Equality &&
204						condition->as<ast::BinaryExpression>().right().getConstant() &&
205						condition->as<ast::BinaryExpression>().right().type->getBitWidth() == 1 &&
206						!condition->as<ast::BinaryExpression>().right().getConstant()->hasUnknown() &&
207						condition->as<ast::BinaryExpression>().right().getConstant()->isTrue()) {
208					auto &biop = condition->as<ast::BinaryExpression>();
209					did_something = true;
210					condition = &biop.left();
211				}
212	
213				if (condition->kind == ast::ExpressionKind::BinaryOp &&
214						condition->as<ast::BinaryExpression>().op == ast::BinaryOperator::Equality &&
215						condition->as<ast::BinaryExpression>().right().getConstant() &&
216						!condition->as<ast::BinaryExpression>().right().getConstant()->hasUnknown() &&
217						condition->as<ast::BinaryExpression>().right().getConstant()->isFalse()) {
218					auto &biop = condition->as<ast::BinaryExpression>();
219					polarity = !polarity;
220					did_something = true;
221					condition = &biop.left();
222				}
223	
224				if (condition->kind == ast::ExpressionKind::Conversion &&
225						condition->as<ast::ConversionExpression>().operand().type->isIntegral() &&
226						condition->as<ast::ConversionExpression>().operand().type->getBitWidth() <
227								condition->type->getBitWidth()) {
228					did_something = true;
229					condition = &condition->as<ast::ConversionExpression>().operand();
230				}
231			}
232	
233			VariableBits condition1 = eval.lhs(*condition, /* silent= */ true);
234	
235			if (condition1.bitwidth() == 1 && !condition1.has_dummy_bits()) {
236				auto found = std::find_if(
237						triggers.begin(), triggers.end(), [&](const ast::SignalEventControl *trigger) {
238							return eval.lhs(trigger->expr, /* silent= */ true) == condition1;
239						});
240	
241				if (found != triggers.end()) {
242					if ((*found)->iffCondition)
243						issuer.add_diag(diag::IffUnsupported, (*found)->iffCondition->sourceRange);
244	
245					if ((*found)->edge !=
246							(polarity ? ast::EdgeKind::PosEdge : ast::EdgeKind::NegEdge)) {
247						auto &diag = issuer.add_diag(
248								diag::IfElseAloadPolarity, cond_stmt.conditions[0].expr->sourceRange);
249						diag.addNote(diag::NoteSignalEvent, (*found)->sourceRange);
250						diag.addNote(diag::NoteDuplicateEdgeSense, timed.timing.sourceRange);
251						// We raised an error. Do infer the async load anyway
252					}
253	
254					found_async.push_back({condition1[0], polarity, cond_stmt.ifTrue});
255					triggers.erase(found);
256					stmt = cond_stmt.ifFalse;
257					continue;
258				}
259			}
260	
261			auto &diag = issuer.add_diag(diag::IfElseAloadMismatch, stmt->sourceRange);
262			diag.addNote(diag::NoteDuplicateEdgeSense, timed.timing.sourceRange);
263			return;
264		}
265	
266		handle_ff_process(symbol, *triggers[0], prologue_block, prologue, *stmt, found_async);
267	}
268	
269	void TimingPatternInterpretor::interpret(const ast::ProceduralBlockSymbol &symbol)
270	{
271		auto kind = symbol.procedureKind;
272		switch (kind) {
273		case ast::ProceduralBlockKind::Always:
274		case ast::ProceduralBlockKind::AlwaysFF: handle_always(symbol); break;
275	
276		case ast::ProceduralBlockKind::AlwaysComb:
277		case ast::ProceduralBlockKind::AlwaysLatch:
278			handle_comb_like_process(symbol, symbol.getBody());
279			break;
280	
281		case ast::ProceduralBlockKind::Initial: handle_initial_process(symbol, symbol.getBody()); break;
282	
283		case ast::ProceduralBlockKind::Final:
284			// Final blocks are ignored by synthesis
285			break;
286	
287		default: log_abort();
288		}
289	}
